What does this program print?

```cpp
#include <iostream>
struct V {
    int x;
    V(int x) : x{x} {}
    V& operator+=(const V& rhs) { x += rhs.x; return *this; }
};
std::ostream& operator<<(std::ostream& o, const V& v) {
    o << v.x; return o;
}
int main() {
    V a{3};
    V b{4};
    a += b;
    std::cout << a << '\n';
}
```

